    "id": "234",
    "title": "What is Empty Calories?",
    "category": "Diabetes",
    "subType": "Tips",
    "mediaType": "static",
    "videoUrl": "https://www.youtube.com/watch?v=veQT2b2NBR4",
    "videoType": "youtube",
